import { GetServerSideProps, NextPage } from 'next';

import { PaymentErrorPage } from '@/payments/pages';
import { Page } from '~/components';
import { GetPaymentQuery, GetPaymentDocument } from 'graphql.schema';

type ErrorPageProps = {
  errorMessage?: string | null;
  redirectUrlSSR?: string | null;
  failureUrlSSR?: string | null;
};

const Error: NextPage<ErrorPageProps> = ({ errorMessage, redirectUrlSSR, failureUrlSSR }) => (
  <Page title="Payment Error">
    <PaymentErrorPage
      errorMessage={errorMessage ?? undefined}
      redirectUrlSSR={redirectUrlSSR ?? undefined}
      failureUrlSSR={failureUrlSSR ?? undefined}
    />
  </Page>
);

export const getServerSideProps: GetServerSideProps = async ({ req, query, params }) => {
  const token = params?.token;
  const errorMessage =
    typeof query?.errorMessage === 'string' ? query?.errorMessage : query?.errorMessage?.[0];

  const { data } = await req.apolloClient.query<GetPaymentQuery>({
    query: GetPaymentDocument,
    variables: {
      input: {
        paymentToken: token,
      },
    },
    errorPolicy: 'all',
  });

  return {
    props: {
      errorMessage: errorMessage || null,
      redirectUrlSSR: data?.getPayment?.integrationProfile?.ui?.redirectUrl ?? null,
      failureUrlSSR: data?.getPayment?.integrationProfile?.ui?.failureUrl ?? null,
    },
  };
};

export default Error;
